INSERT INTO public.photos VALUES (23079, 'Azud del Ebro 2007', 'El azud "Manuel Lorenzo Pardo" (fundador de la CHE) es denominado tambiâ”śÂ®n como "Azud del Ebro", si bien su utilidad social es la de "Pasarela peatonal". Fue ideado y construido con motivo de la ExpoZaragoza 2008, y tenâ”śÂˇa como primer objetivo garantizar una pelâ”śÂˇcula estable de agua para la navegaciâ”śâ”‚n de ocio entre Vadorrey y el meandro de Ranillas. Incluâ”śÂˇa, como segunda funciâ”śâ”‚n, una pasarela peatonal entre Vadorrey y Las Fuentes. La navegabilidad del Ebro asociada a este proyecto ha hecho aguas, como no podâ”śÂˇa ser de otra forma. La secundaria pasarela peatonal es desde hace tiempo su mâ”śĂ­s destacada funciâ”śâ”‚n social, como no podâ”śÂˇa ser de otra forma. En la imagen, los enormes pilares hormigonados donde encajar luego las siete compuertas abatibles de 23,85 metros de largo c/u. Al fondo, los bloques ribereâ”śâ–’os de Vadorrey-Nobleza Baturra. Foto: Ana Muller. Fuente: "Razâ”śâ”‚n y sed", Colegio de Ingenieros de Caminos, Canales y Puertos, 2008.', 2007, 2007, 2007, 'Siglo XXI', 'LAS FUENTES', 41.65193500, -0.85745900, '0101000020E6100000CC2555DB4D70EBBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16626138720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16626138720.webp', 'https://www.flickr.com/photos/zaragozaantigua/16626138720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22338, 'Piscina SD Arenas 1969', 'En la piscina de la Sociedad Deportiva Arenas (en la denominada Ciudad Deportiva â”¬Â˝Martâ”śÂˇn-Celimâ”śÂ®ndizâ”¬â•—, inaugurada un par de aâ”śâ–’os antes), allâ”śĂ­ por el lejano sureste de la ciudad (Barrio de San Josâ”śÂ®), en julio de 1969 tuvo lugar una competiciâ”śâ”‚n de nado entre las selecciones "B" de Espaâ”śâ–’a e Italia. Acudiâ”śâ”‚ mucho pâ”śâ•‘blico y autoridades, entre las que se encontraba el Câ”śâ”‚nsul de la Repâ”śâ•‘blica de Italia, Sr. Carlos Baratto. Ganâ”śâ”‚ el seleccionado espaâ”śâ–’ol por el câ”śâ”‚mputo global de 61 a 40. Esta piscina era de las poquitas que en toda la ciudad, en aquellos aâ”śâ–’os, podâ”śÂˇan albergar una competiciâ”śâ”‚n de esta categorâ”śÂˇa. Este evento se desarrollâ”śâ”‚ a pocos metros del Cabezo Cortado, el Canal Imperial, y las graveras de La Paz. La imagen presenta una panorâ”śĂ­mica de las humildes viviendas del entorno a la piscina, en lo que fuera la antigua "Barriada de Argentina", en las actuales calles Argentina, Hermanos Machado, Melilla, Juan XXII... La "Piscina del Arenas" estâ”śĂ­ cerrada desde hace bastantes aâ”śâ–’os, a la espera de que alguno de los sucesivos propietarios del suelo arranque a urbanizar una zona anclada en el tiempo que, mientras tanto, ejerce de especulativo barbecho expectante. Eso que se intuye al fondo a la derecha, efectivamente, es el Pilar. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63155400, -0.87287600, '0101000020E610000052D32EA699EEEBBF39D4EFC2D6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20047465630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20047465630.webp', 'https://www.flickr.com/photos/zaragozaantigua/20047465630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22498, 'Cabezo Cortado c.1963', 'Imagen capturada desde la natural altura del Cabezo Cortado caracterâ”śÂˇstica con sus bien pobrecicos pinos, porque la cascajera que lo conforma no da para mâ”śĂ­s, con una extraordinaria vista panorâ”śĂ­mica de la ciudad desde esta atalaya sita en el sureste e inmediata al Canal Imperial de Aragâ”śâ”‚n. En primer tâ”śÂ®rmino, algunos feraces campos de herbâ”śĂ­ceas donde pocos aâ”śâ–’os despuâ”śÂ®s se ubicarâ”śÂˇa la Ciudad Deportiva Martâ”śÂˇn-Celimâ”śÂ®ndiz, muy popular por la exclusiva y monumental piscina de la SD Arenas, durante unos aâ”śâ–’os la â”śâ•‘nica de gran categorâ”śÂˇa en toda la ciudad. Justo detrâ”śĂ­s, inmuebles de la antigua barriada de Argentina, vertebrada por las calle de Argentina, Hermanos Machado, Melilla y Juan XXII. Tras ella, diversos entornos del barrio de San Josâ”śÂ®, desde la izquierda, donde destaca la fâ”śĂ­brica de La Zaragozana, hasta la trinchera del ferrocarril a la derecha, flanqueada por el Grupo de Viviendas Puente Virrey-Rosellâ”śâ”‚n; las parcelicas de las calles de Mario, Nobleza y Alegrâ”śÂˇa, junto a al calle de la Cadena de la Granja; el triangular Grupo de Viviendas Agustâ”śÂˇn Gericâ”śâ”‚ en la calle de Josâ”śÂ® Galiay; y la antigua Granja Agrâ”śÂˇcola de Zaragoza. El telâ”śâ”‚n de fondo lo jalonan algunas de las torre y câ”śâ•‘pulas de la antigua ciudad, en este caso ya acompaâ”śâ–’adas de las dos nuevas torres ribereâ”śâ–’as del templo del Pilar, y con la progresiva incorporaciâ”śâ”‚n de los grandes bloques de viviendas que desde finales de la dâ”śÂ®cada de los grises aâ”śâ–’os 50 van surgiendo por doquiera les pareciera a sus emprendedores promotores. Al fondo y a la derecha emerge la tambiâ”śÂ®n natural atalaya natural del Cascajo. Desde el Gran Archivo Zaragoza antigua hemos volteado horizontalmente la original imagen para que recobrara el sentido de la orientaciâ”śâ”‚n perdida.', 1963, 1963, 1963, 'Anos 60', 'TORRERO', 41.63080000, -0.87297300, '0101000020E6100000F04FA91265EFEBBF8D28ED0DBED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49029831276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49029831276.webp', 'https://www.flickr.com/photos/zaragozaantigua/49029831276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23142, 'Cabezo Cortado 2009', 'De toda la vida, el Cabezo Cortado ha sido uno de los miradores privilegiados desde cuya altura mejor se contemplaba el esplâ”śÂ®ndido panorama de Zaragoza. En 1901 asâ”śÂˇ lo ratificaron los prâ”śÂˇncipes de Asturias, que en su visita a la ciudad no dejaron de peregrinar a este lugar. Mâ”śĂ­s tarde, el Desarrollismo de la segunda mitad del siglo XX dejâ”śâ”‚ al lugar progresivamente bastante maltrecho. En el arranque del siglo XXI (2006), las denuncias de "abandono" seâ”śâ–’alaron la responsabilidad municipal, que respondiâ”śâ”‚ aclarando que el Cabezo no sâ”śâ”‚lo no se encontraba en abandono, sino que tenâ”śÂˇa en marcha un proceso administrativo para su mejora y completa remodelaciâ”śâ”‚n, como parte de un â”śĂ­rea de desarrollo urbano de iniciativa privada que ya tenâ”śÂˇa proyecto, en fase de tramitaciâ”śâ”‚n muy avanzada. La extraordinaria ola de la Expo 2008 pasâ”śâ”‚, y el Cabezo permaneciâ”śâ”‚ estable, junto al â”śâ•‘nico tramo del Canal Imperial a su paso por Zaragoza que no conoce, apenas, intervenciones de dignificaciâ”śâ”‚n. La imagen se corresponde con un proyecto de 2009 para la urbanizaciâ”śâ”‚n del sector F-38/1, o zona del Cabezo Cortado segâ”śâ•‘n el vigente PGOU, representada en color verde claro, porque habrâ”śÂˇa de ser de "câ”śÂ®sped". En verde oscuro, la zona de pronunciados taludes, arbolada. Al norte, el desarrollo urbanâ”śÂˇstico previsto hasta el camino de Miraflores. Al este, el alabeado enlace con el Tercer Cinturâ”śâ”‚n. Al sur, el cauce del Canal Imperial. Mientras tanto, hemos llegado al aâ”śâ–’o 2017.', 2009, 2009, 2009, 'Siglo XXI', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31842078500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31842078500.webp', 'https://www.flickr.com/photos/zaragozaantigua/31842078500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23224, 'Cabezo Cortado 2017', 'Propuesta de intervenciâ”śâ”‚n urbana en el sector F-38-1 del barrio de San Josâ”śÂ® centrado en la realizaciâ”śâ”‚n, en primer tâ”śÂ®rmino, de un parque en el Cabezo Cortado y su conexiâ”śâ”‚n con el Jardâ”śÂˇn o Parque de la Memoria mediante un "Eje Verde" a travâ”śÂ®s de la prolongaciâ”śâ”‚n de la calle de Melilla y el camino de Miraflores. Se incluyen varios bloques de viviendas para completar manzanas incompletas, ademâ”śĂ­s de algunas infraestructuras de barrio como una biblioteca o un centro de dâ”śÂˇa. Esta propuesta estaba incluida en el Mâ”śĂ­ster Universitario en Arquitectura de la Universidad de Zaragoza realizado en el curso 2016-17, y publicado por la colaboraciâ”śâ”‚n entre la municipal Sociedad Municipal Zaragoza Vivienda y la Escuela de Ingenierâ”śÂˇa y Arquitectura de la Universidad de Zaragoza. Como otras varias propuestas centradas en la revitalizaciâ”śâ”‚n del entorno del Cabezo Cortado desde que las obras de acompaâ”śâ–’amiento de la Expo 2008 pasaran de largo por aquâ”śÂˇ, estas musas nunca llegaron al teatro.', 2017, 2017, 2017, 'Siglo XXI', 'TORRERO', 41.63098500, -0.87303700, '0101000020E61000009F55664AEBEFEBBF1FA2D11DC4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51359634607.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51359634607.webp', 'https://www.flickr.com/photos/zaragozaantigua/51359634607/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23353, 'Acueducto Barranco de la Muerte 2001', 'Foto Heraldo de Aragâ”śâ”‚n/Guillermo Mestre, 2001. Barranco de la Muerte de Zaragoza. Ronda de la Hispanidad o Tercer Cinturâ”śâ”‚n, inaugurado en 2003. Construcciâ”śâ”‚n del acueducto de Javier Manterola del Canal Imperial de Aragâ”śâ”‚n -finalizado en 2002- con la idea de desviar la vâ”śÂˇa acuâ”śĂ­tica unos metros para derribar el levantado por Ramâ”śâ”‚n Pignatelli en 1790. Al final no se derribâ”śâ”‚ el anterior, practicâ”śĂ­ndole unos ojos por los que discurren los seis carriles carreteros. Lo cual da como resultado dos acueductos para un solo canal: el antiguo, desecado; y el nuevo, con agua.', 2001, 2001, 2001, 'Siglo XXI', 'TORRERO', 41.62310800, -0.87288200, '0101000020E6100000DB8B683BA6EEEBBF20F0C000C2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940093608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940093608.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940093608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23354, 'Acueducto Barranco de la Muerte 1833', '"Obras del Barranco de la Muerte". En 1790 se levantâ”śâ”‚ el acueducto para que el Canal Imperial de Aragâ”śâ”‚n de Ramâ”śâ”‚n Pignatelli salvase el Barranco de la Muerte de los montes de Torrero de Zaragoza. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.62362300, -0.87158300, '0101000020E610000076FC170802E4EBBF4704E3E0D2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14941492129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14941492129.webp', 'https://www.flickr.com/photos/zaragozaantigua/14941492129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23358, 'Acueducto del Barranco de la Muerte 2002', 'Foto Ayuntamiento de Zaragoza. Fase final de las obras de acondicionamiento del Acueducto de Pignatelli (Canal Imperial) sobre el Barranco de la Muerte de Zaragoza, abriâ”śÂ®ndole dos grandes ojos para el paso de los vehâ”śÂˇculos por el Tercer Cinturâ”śâ”‚n de ronda. Despuâ”śÂ®s hubo que reforzarle los cimientos porque peligraba la estructura.', 2002, 2002, 2002, 'Siglo XXI', 'TORRERO', 41.62367400, -0.87170400, '0101000020E6100000365B79C9FFE4EBBFC9AEB48CD4CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114442256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114442256.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114442256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23388, 'Embarcadero La Paz 2008', 'Construcciâ”śâ”‚n del embarcadero del Canal Imperial de Aragâ”śâ”‚n en el barrio de La Paz, cerca del campo de fâ”śâ•‘tbol Josâ”śÂ® Luis Violeta (al fondo). La obra se enmarcaba en un plan abortado para volver a hacer navegable el Canal en Zaragoza, con cuatro embarcaderos: â”śÂ®ste, el de la calle â”śĂĽfrica, el de Valdefierro y el de los depâ”śâ”‚sitos de Casablanca, esclusa incluida. Todo ello en el marco del plan de riberas de la Expo 2008. Fuente: Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'TORRERO', 41.62678700, -0.87177300, '0101000020E61000005725917D90E5EBBF6B47718E3AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31899460223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31899460223.webp', 'https://www.flickr.com/photos/zaragozaantigua/31899460223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23398, 'Vista aâ”śÂ®rea 2001', 'Vista aâ”śÂ®rea del sureste de Zaragoza donde se resalta el sinuoso terroso trazado del previsto Tercer Cinturâ”śâ”‚n de Ronda ya en obras que a la izquierda y desde el fondo asciende por los Pinares de Venecia hasta el entorno del cementerio de Torrero, desciende luego hasta el cruce con el Canal Imperial de Aragâ”śâ”‚n, donde se estâ”śĂ­ procediendo en primer tâ”śÂ®rmino a construir un nuevo puente-acueducto del barranco de la Muerte, de trazado mâ”śĂ­s rectilâ”śÂˇneo que el ilustrado. Esta zona se muestra con un aspecto radicalmente modificado despuâ”śÂ®s cuando el desarrollo de Parque Venecia. Finalmente, el trazado del cinturâ”śâ”‚n prosigue separando la frondosa antigua Quinta Julieta del erial donde estuvo el desmantelado gueto de ese mismo nombre, hasta el cruce sobre las vâ”śÂˇas del ferrocarril, todavâ”śÂˇa pendiente veinte aâ”śâ–’os despuâ”śÂ®s de un enlace digno con el barrio de San Josâ”śÂ® que no sea el inadecuado camino de Miraflores.', 2001, 2001, 2001, 'Siglo XXI', 'TORRERO', 41.62455300, -0.87216800, '0101000020E61000006EC493DDCCE8EBBF31CF4A5AF1CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51495497238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51495497238.webp', 'https://www.flickr.com/photos/zaragozaantigua/51495497238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24565, 'Vista de Zaragoza 1908', '1908. "Vista de Zaragoza", â”śâ”‚leo de Juan Josâ”śÂ® Gâ”śĂ­rate pintado al albur de la Exposiciâ”śâ”‚n Hispano Francesa impulsada, a la par, por la vieja aristocracia financiera y la nueva burguesâ”śÂˇa industrial local. Esta "vista" topogrâ”śĂ­fica de la ciudad, el pintor la sitâ”śâ•‘a con el caballete montado en la altura del Cabezo Cortado, natural atalaya urbana desde hace milenios. La descripciâ”śâ”‚n canâ”śâ”‚nica de la pintura destaca fundamentalmente la presencia, juntos, pero no revueltos, de tipos populares y baturros joteros al lado de una notable galerâ”śÂˇa de prohombres locales y regionales (entre otros, Mariano de Cavia, Basilio Paraâ”śÂˇso, Segismundo Moret, Santiago Ramâ”śâ”‚n y Cajal, Francisco Pradilla, y el propio autor, en notable e irrepetible galerâ”śÂˇa de prâ”śâ”‚ceres). Una lupa urbana nos aporta algunos elementos caracterâ”śÂˇsticos de lo que desde el Cabezo Cortado podâ”śÂˇa entonces verse: a la derecha, la mole imponente del edificio de la Granja Agrâ”śÂˇcola Experimental, rodeada de sus extensos y experimentales campos de cultivo. Un poco antes, la reciente lâ”śÂˇnea de los ferrocarriles directos a Barcelona, con el novâ”śÂˇsimo apeadero de Miraflores. El espacio aâ”śâ•‘n verde de la huerta de Miraflores, delimitado por la trinchera del ferrocarril, el Camino de las Torres, el Camino de S. Josâ”śÂ®. Unos alrededores de aspecto agrâ”śÂˇcola, hortelano, perifâ”śÂ®rico, tranquilo, silencioso, despejado y anâ”śâ”‚nimo. Tan cerca y tan lejos de la ciudad que, al fondo, reluce al atardecer con su linea del cielo de torres, câ”śâ•‘pulas, y la sombra de alguna chimenea.', 1908, 1908, 1908, 'Anos 1900', 'TORRERO', 41.63039900, -0.87214100, '0101000020E61000000806103E94E8EBBF2E3718EAB0D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875626383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875626383.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875626383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24574, 'Cabezo Cortado 1915', 'Imagen panorâ”śĂ­mica capturada, hacia 1915, desde el mirador natural del Cabezo Cortado. A la izquierda, inmediatas, las obras de construcciâ”śâ”‚n del "Sanatorio de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar" para niâ”śâ–’os tuberculosos. Un poco mâ”śĂ­s abajo, en descenso, las primeras construcciones del "Barrio de la Argentina", y parcelas del "Barrio de Cuber". Los pabellones principales de la Granja quedan a la derecha, entre campos de cultivo y moreras. Al fondo, entre tinieblas, emergen algunas torres de la lejana ciudad. Fuente visual: AVV. San Josâ”śÂ®.', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20396578695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20396578695.webp', 'https://www.flickr.com/photos/zaragozaantigua/20396578695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24575, 'Cabezo Cortado 1927', '"Panorâ”śĂ­mica de la ciudad de Zaragoza" capturada desde las alturas del Cabezo Cortado. A la izquierda, construcciones del "Barrio de la Argentina" y del "Barrio de Cuber". En el centro, aterrazados y herbâ”śĂ­ceos campos de cultivo de La Granja, y ordenados camino de moreras en las inmediaciones de sus pabellones principales, que quedan a la derecha, fuera de plano. El arbolado Camino del Puente del Virrey, atravesado por la trinchera del ferrocarril a Barcelona. Al fondo, algunas de las torres y câ”śâ•‘pulas de la lejana ciudad. Fuente visual: AHPZ, Archivo Gabriel Faci', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21553628792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21553628792.webp', 'https://www.flickr.com/photos/zaragozaantigua/21553628792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25719, 'Vista desde el Cabezo Cortado 1969', 'Imagen del progresivo estiramiento vertical de las construcciones de la ciudad o, lo que es lo mismo, de la creciente dificultad en encontrar esas panorâ”śĂ­micas urbanas tan diâ”śĂ­fanas de apenas unas pocas dâ”śÂ®cada antes. La visual desde el Cabezo Cortado sigue siendo espectacular, pero a los tâ”śâ”‚tems "de toda la vida", ergo las torres del Pilar (como mucho, dos de ellas) y de la Seo, les van saliendo competidores por doquiera se mire. Y aâ”śâ•‘n faltan por llegar las construcciones de los 70, de los 80... En primer plano, campos de cultivo que fueron de la Granja Agrâ”śÂˇcola, y a su izquierda, los bloques de viviendas de la calle Rosellâ”śâ”‚n. Delante, la trinchera del ferrocarril, y el puentecillo peatonal hacia Luis Aula y Josâ”śÂ® Galiay. Las parcelitas de las calle Nobleza, Alegrâ”śÂˇa, Emilio-Mario... y las naves industriales de Escultor Moreto y la calle Cadena de la Granja. Las traseras de los bloques de la calle Raquel Meller... La mole del Depâ”śâ”‚sito del Gas, es visible desde casi cualquier parte. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239283934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239283934.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239283934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25723, 'Cabezo Cortado c.1877', '"Zaragoza: Vista general tomada desde el Cabezo Cortado". Jean Laurent. Una extraordinaria vista panorâ”śĂ­mica, que tal vez merece ser catalogada de "monumento visual" de la ciudad, con las torres y câ”śâ•‘pulas al fondo, por supuesto, perfectamente reconocibles, pero con todo un paisaje y un verdor ubâ”śÂ®rrimo que desde la atalaya natural del Cabezo Cortado, y en el momento de capturar esta imagen, alcanzaba hasta la desembocadura del Huerva, y mâ”śĂ­s allâ”śĂ­. Asâ”śÂˇ lucâ”śÂˇa la periferia del sureste de la ciudad. De izquierda a derecha, una insâ”śâ”‚lita visual del camino del Puente del Virrey, ya con una instalaciâ”śâ”‚n fabril en su parte superior, donde la torre de Cuber, y el alabeado cauce en descenso de la nueva acequia del Plano. Ya en 1892 alguna torre desaparecerâ”śÂˇa del horizonte, derribada, y otras construcciones mâ”śĂ­s modernas comenzarâ”śÂˇan a proliferar. En la segunda mitad del pasado siglo XX, el aquâ”śÂˇ dominante tono verde fue dejando paso, de forma fulminante, a la urbanizaciâ”śâ”‚n mâ”śĂ­s desbocada, que ha modificado de forma radical lo que desde aquâ”śÂˇ se puede ver hoy. Con todo, mucho tiempo despuâ”śÂ®s, el Cabezo Cortado sigue siendo un interesante mirador natural, aunque muy venido a menos por la degradaciâ”śâ”‚n, el abandono, y la poca voluntad municipal a la hora de dignificarlo. Su compaâ”śâ–’ero de Buenavista ha tenido mâ”śĂ­s fortuna. Fuente visual: www.mcu.es/ (Archivo Ruiz Vernacci)', 1877, 1877, 1877, 'Siglo XIX', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20041953410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20041953410.webp', 'https://www.flickr.com/photos/zaragozaantigua/20041953410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25956, 'Quinta Julieta c.1985', 'Vista aâ”śÂ®rea del poblado gitano Quinta Julieta, cuya denominaciâ”śâ”‚n se tomâ”śâ”‚ prestada de la finca de recreo prâ”śâ”‚xima. Fue construido en 1981 con la intenciâ”śâ”‚n de erradicar el chabolismo. En 1982 se trasladaron allâ”śÂˇ 140 familias, convirtiâ”śÂ®ndose en foco de conflictos. En 1986 se constatâ”śâ”‚ el fracaso de la iniciativa, derribâ”śĂ­ndose por completo. En la imagen, a la izquierda, el Canal Imperial de Aragâ”śâ”‚n. En el â”śĂ­ngulo superior izquierdo, viviendas en la calle de Alhama de Aragâ”śâ”‚n del barrio de Torrero. La configuraciâ”śâ”‚n de este entorno en su zona norte ha cambiado radicalmente con la construcciâ”śâ”‚n del Tercer Cinturâ”śâ”‚n y el desvâ”śÂˇo del Canal a su paso por el Barranco de la Muerte, aunque el solar donde se levantaba el gueto continâ”śâ•‘a en barbecho. Fuente visual: Foto: Archivo Taumar (Irene Taules y Rafael Margalâ”śÂ®), en www.facebook.com/photo.php?fbid=1797322197158145&set=...', 1985, 1985, 1985, 'Anos 80', 'TORRERO', 41.62262500, -0.87011900, '0101000020E6100000691A14CD03D8EBBF04560E2DB2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36717050274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36717050274.webp', 'https://www.flickr.com/photos/zaragozaantigua/36717050274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23376, 'Almenara de San Antonio 1833', '"Almenara de San Antonio de Padua", litografâ”śÂˇa de Faramundo Blanchard. Esta almenara se encuentra en el actual barrio de San Josâ”śÂ® de Zaragoza, junto al escorredero de la Media Legua. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.61713300, -0.86410100, '0101000020E6100000D21BEE23B7A6EBBF2524D236FECE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20342130452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20342130452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20342130452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23966, 'Monumento a la Legiâ”śâ”‚n 1974', 'Inauguraciâ”śâ”‚n oficial, el 15 de octubre de 1974, del Monumento Nacional a los muertos de la Legiâ”śâ”‚n, con presencia de Su Alteza Real el Principe Don Juan Carlos de Borbâ”śâ”‚n,al fondo. En la imagen, y tras la bendiciâ”śâ”‚n del monumento y el descubrimiento de la lâ”śĂ­pida conmemorativa, ceremonia de la misa oficiada sobre el basamento que alberga una cripta. En posiciâ”śâ”‚n de saludo y en el centro, el Ministro del Ejâ”śÂ®rcito, Francisco Coloma Gallegos. Despuâ”śÂ®s fue el turno de los discursos, a cargo del coronel Caparrâ”śâ”‚s como presidente de la Hermandad de Antiguos Caballeros Legionarios de Zaragoza, entidad promotora; del alcalde Mariano Horno Liria; y del Ministro del Ejâ”śÂ®rcito. Este monumento costâ”śâ”‚ 6 millones de pesetas, sufragado por suscripciâ”śâ”‚n popular, mâ”śĂ­s una subvenciâ”śâ”‚n del Estado, y fue erigido en terreno municipal en los Pinares de Venecia, frente al Parque de Atracciones.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.62234000, -0.90071400, '0101000020E61000003A94A12AA6D2ECBF0F7F4DD6A8CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022691281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022691281.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022691281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25193, 'Parque de Atracciones 2007', 'Plano guâ”śÂˇa del Parque de Atracciones de Zaragoza, 2007. Este complejo de ocio fue inaugurado en 1974, en los Pinares de Venecia del monte de Torrero de Zaragoza.', 2007, 2007, 2007, 'Siglo XXI', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20703638246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20703638246.webp', 'https://www.flickr.com/photos/zaragozaantigua/20703638246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25946, 'Carlos Mejâ”śÂˇa Godoy 1977', 'Acuaciâ”śâ”‚n de Carlos Mejâ”śÂˇa Godoy y Los de Palacagâ”śâ•ťina en el Parque de Atracciones de Zaragoza. Fuente: www.facebook.com/photo.php?fbid=10205798525379308&set...', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22537242682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22537242682.webp', 'https://www.flickr.com/photos/zaragozaantigua/22537242682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25950, 'Parque de Atracciones c.1983', 'Foto para postal del Parque de Atracciones, inaugurado en 1974 en el monte de Torrero. Al fondo, el Monumento a la Legiâ”śâ”‚n y los edificios de la Romareda y Universidad, tras el parque Primo de Rivera. Fuente: www.todocoleccion.net', 1983, 1983, 1983, 'Anos 80', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27233996719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27233996719.webp', 'https://www.flickr.com/photos/zaragozaantigua/27233996719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21055, 'Puente de Amâ”śÂ®rica c.1870', 'Museo del Prado. Antes de 1880. Imagen del primitivo Puente de Amâ”śÂ®rica sobre el Canal Imperial, construido por militares del ejâ”śÂ®rcito de Tierra, del Regimiento que llevaba ese nombre ("Amâ”śÂ®rica"), en el aâ”śâ–’o 1815, en la Playa de Torrero, en un vado del Canal que se usaba para acceder a las canteras localizadas en lo que hoy es la Avenida de Amâ”śÂ®rica. Este puente, de fâ”śĂ­brica en piedra, mamposterâ”śÂˇa y ladrillo, sin grandes alardes estilâ”śÂˇsticos, fue luego restaurado varias veces a lo largo de siglo XIX, hasta que en en 1901 se plantea su demoliciâ”śâ”‚n y la construcciâ”śâ”‚n de un nuevo Puente, metâ”śĂ­lico y mâ”śĂ­s estiloso. El actual, que se construyâ”śâ”‚ en 1903. El puente de la imagen es el que aparece en la excepcional serie de grabados que en el aâ”śâ–’o 1833 jalona todas las grandes obras de acompaâ”śâ–’amiento (almenaras, puentes, presas, viaductos, esclusas...) del Canal Imperial de Aragâ”śâ”‚n. En la imagen se recoge ademâ”śĂ­s, a la izquierda, la enorme entrada al dique de carena del puerto de Miraflores, el estado de las riberas, el camino de sirga, y embarcaciones que recuerdan que esa era una de las funciones principales del Canal: la navegaciâ”śâ”‚n.', 1870, 1870, 1870, 'Siglo XIX', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858414484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858414484.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858414484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21164, 'Puente de Amâ”śÂ®rica 1894', '"Canal Imperial de Pignatelli y el puente de Amâ”śÂ®rica", un dibujo de J. Serra Pausas. En la imagen, el antiguo Puente de Amâ”śÂ®rica sobre el Canal Imperial, construido en 1815 y restaurado varias veces a lo largo de siglo XIX. A la izquierda, la monumental entrada al dique de carena del proyectado puerto de Miraflores, y algunas embarcaciones. A la derecha, la "Playa de Torrero" como lugar de paseo, encuentro, y festejo ciudadano. Fuente: "La Ilustraciâ”śâ”‚n Ibâ”śÂ®rica", Barcelona.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63330200, -0.88454900, '0101000020E610000042B456B4394EECBFE63E390A10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20921975008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20921975008.webp', 'https://www.flickr.com/photos/zaragozaantigua/20921975008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21174, 'Puente de Amâ”śÂ®rica c.1898', 'Imagen del decimonâ”śâ”‚nico puente de Amâ”śÂ®rica sobre el Canal Imperial. A la izquierda, la dâ”śĂ­rsena para reparaciâ”śâ”‚n de embarcaciones. Al fondo, a la derecha, la harinera de Monares. Fuente visual: www.ebay.es/', 1898, 1898, 1898, 'Siglo XIX', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31133290343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31133290343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31133290343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21200, 'Puente de Amâ”śÂ®rica c.1898', 'Desde la playa de Torrero, imagen del decimonâ”śâ”‚nico Puente de Amâ”śÂ®rica sobre el Canal Imperial de Aragâ”śâ”‚n y el anexo dique seco para embarcaciones canalinas. En primer tâ”śÂ®rmino y a la derecha, posado de unos simpâ”śĂ­ticos personajes. En la rampa de bajada al canal entre le puente y el dique, lavanderas faenando.', 1898, 1898, 1898, 'Siglo XIX', 'TORRERO', 41.63325400, -0.88506400, '0101000020E610000001BEDBBC7152ECBFD50792770ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53535438475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53535438475.webp', 'https://www.flickr.com/photos/zaragozaantigua/53535438475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21203, 'Playa de Torrero 1894', 'Imagen capturada junto al estribo izquierdo recayente a la playa de Torrero del puente de Amâ”śÂ®rica, con el objetivo orientado aguas abajo del Canal Imperial de Aragâ”śâ”‚n. A la derecha, barcaza de la empresa canalina estacionada junto a la chopera y viveros que daban continuidad a los diques para embarcaciones. A la izquierda, orilla del canal desprovista de barandilla y zona de paseo delimitada por ilustrados plâ”śĂ­tanos de sombra. Al fondo, la gran casa de Pablo Salvador Lâ”śâ”‚pez que con su aspecto monumental cerraba la vista de este tranquilo entorno disfrutable tan lejos y tan cerca de la ciudad.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63319200, -0.88453700, '0101000020E61000003143E389204EECBF5F0B7A6F0CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54197148116.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54197148116.webp', 'https://www.flickr.com/photos/zaragozaantigua/54197148116/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21210, 'Vista de Zaragoza c.1900', 'Comienzos del siglo XX. Foto coloreada, tomada siguiendo el cauce de la antigua Acequia del Presidio, y la mâ”śĂ­s moderna Acequia de El Plano, donde se acababa de instalar "La Zaragozana, Fâ”śĂ­brica de Cerveza, Malta y Hielo" (1900). Tenemos una visual inmediata del Camino de las Alcachoferas, de la trinchera del ferrocarril de los directos a Barcelona (el pretil de piedra que recorre los campos de W-E, a mitad de imagen), y los campos de cereal, maâ”śÂˇz y herbâ”śĂ­ceas regados desde la Acequia de las Adulas, que acompaâ”śâ–’a al camino de las Torres (a la izquierda), y que posibilitâ”śâ”‚ que en esta zona se instalaran varios ingenios fabriles, como molinos de aceite, sierra de mâ”śĂ­rmol, harineras, curtidoras, y a la altura de la torre de La Magdalena, las instalaciones de la Fâ”śĂ­brica de Gas. El antiguo convento de San Josâ”śÂ® de los Carmelitas Descalzos, en esta imagen realizaba las funciones de Penal.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63331800, -0.88018200, '0101000020E610000054E41071732AECBFECFB709010D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958791625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958791625.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958791625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21250, 'Cuartel de Castillejos c.1900', 'Entre 1896 y 1910, el Cuartel de Torrero, o de los Castillejos, fue ocupado por el Regimiento de Lanceros del Rey (1â”¬â•‘ de Caballerâ”śÂˇa del Ejâ”śÂ®rcito Espaâ”śâ–’ol). En la imagen, algunos de los caballos regimentales abrevan. Al fondo, la iglesia neoclâ”śĂ­sica de San Fernando, castrense capilla. Fuente visual: AHPZ-Archivo Coyne.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20311560512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20311560512.webp', 'https://www.flickr.com/photos/zaragozaantigua/20311560512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21252, 'Puente de Amâ”śÂ®rica c.1905', 'Imagen del nuevo Puente de Amâ”śÂ®rica y la ribera del Canal Imperial. Tras el puente, la dâ”śĂ­rsena para embarcaciones. A este lado del puente, el edificio de viviendas que supervive como nâ”¬â•‘ 1 de la Vâ”śÂˇa de Ramâ”śâ”‚n Pignatelli. Fuente visual: TC, Postal "Cecilio Gasca".', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63315800, -0.88520400, '0101000020E6100000713AC9569753ECBFB39943520BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20455125812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20455125812.webp', 'https://www.flickr.com/photos/zaragozaantigua/20455125812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21293, 'Puente de Amâ”śÂ®rica 1903', 'Imagen del Canal Imperial en el lugar del nuevo puente de Amâ”śÂ®rica, proyectado por Josâ”śÂ® Marâ”śÂˇa Royo Villanova, con un gâ”śĂ­libo rebajado al nivel de la calle para la circulaciâ”śâ”‚n rodada, lo que supuso que la navegabilidad del Canal para las grandes embarcaciones, primordial funciâ”śâ”‚n de esta ilustrada infraestructura, quedara interrumpida en ese punto. La imagen estâ”śĂ­ capturada desde la denominada "playa" del Canal. Inmediata y fuera de plano, a la izquierda, la dâ”śĂ­rsena para reparaciâ”śâ”‚n de embarcaciones en seco. Al fondo, edificios del nuevo barrio de "Venecia". En el momento de realizar esta imagen, la modernista decoraciâ”śâ”‚n de barandillas y farolas, diseâ”śâ–’adas por Ricardo Magdalena Tabuenca, aâ”śâ•‘n no habâ”śÂˇa sido emplazada en su sitio, porque la estaba realizando el rejero Josâ”śÂ® Gonzâ”śĂ­lez. Una vez instalada, el puente fue inaugurado en octubre de ese aâ”śâ–’o. Fuente visual: Fototipia de Lucas Escolâ”śĂ­, serie "Zaragoza", AMZ.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29292547262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29292547262.webp', 'https://www.flickr.com/photos/zaragozaantigua/29292547262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21306, 'Canal Imperial c.1903', 'Imagen capturada junto al Canal Imperial de Aragâ”śâ”‚n en la pronunciada curva donde se deriva agua a la acequia del Ontonar. Al fondo, parte de las antiguas instalaciones de la Playa de Torrero reconvertidas en cuartel del ejâ”śÂ®rcito. La gâ”śâ”‚ndola denominada Santa Cecilia o del Cisne (por la figura tallada en su proa) permanece amarrada en su posiciâ”śâ”‚n de descenso hacia la Quinta de Julieta Sagols, con un posado de sus pasajeros. A la derecha, posiblemente una vendedora del local periâ”śâ”‚dico independiente de dos ediciones diarias fundado en 1895, en su tradicional formato de sâ”śĂ­bana. Fuente visual: Colecciâ”śâ”‚n Montserrat/Sociedad Estereoscâ”śâ”‚pica Espaâ”śâ–’ola (Barcelona), en Zaragoza estereoscâ”śâ”‚pica, fotografâ”śÂˇa profesional y comercial 1850-1970, PUZ.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63273600, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF3D80457EFDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34973623296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34973623296.webp', 'https://www.flickr.com/photos/zaragozaantigua/34973623296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21315, 'Playa de Torrero 1905', 'Dibujo anâ”śâ”‚nimo de la Playa de Torrero, entorno en las inmediaciones del Canal Imperial de Aragâ”śâ”‚n donde se erige un cuartel militar. Fuente: www.elmarcoverde.com', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63363900, -0.88437700, '0101000020E6100000FAB48AFED04CECBF2E3C2F151BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37383811586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37383811586.webp', 'https://www.flickr.com/photos/zaragozaantigua/37383811586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21333, 'Canal Imperial c.1900', 'Imagen capturada junto al Canal Imperial de Aragâ”śâ”‚n a la altura de la almenara de Santa Engracia. Al fondo, el antiguo puente de Amâ”śÂ®rica bajo cuyo ojo aparece una de las barcazas de transporte de mercancâ”śÂˇas por el canal y las casas de Salvador, antecedente de la torre de Dâ”śĂ­maso Pina. A la derecha, el embarcadero del canal.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63357500, -0.88641600, '0101000020E61000001BD65416855DECBF174850FC18D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50938923578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50938923578.webp', 'https://www.flickr.com/photos/zaragozaantigua/50938923578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21348, 'Playa de Torrero 1908', 'Imagen capturada en la playa de Torrero con el fondo del nuevo puente de Amâ”śÂ®rica. A la izquierda y en la margen derecha, chopera y vivero del Canal Imperial de Aragâ”śâ”‚n. A la derecha y entre los veteranos plâ”śĂ­tanos de sombra, postes de suministro elâ”śÂ®ctrico de la efâ”śÂˇmera lâ”śÂˇnea tranviaria del Arenal, de la que un coche se dirige a la terminal.', 1908, 1908, 1908, 'Anos 1900', 'TORRERO', 41.63287700, -0.88211400, '0101000020E6100000F3FFAA23473AECBFFFB1101D02D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54145726724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54145726724.webp', 'https://www.flickr.com/photos/zaragozaantigua/54145726724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21425, 'Merendero del Canal c.1915', 'Posado de Trinidad Cordero Adâ”śĂ­n y Francisca Adâ”śĂ­n Bayod a la orilla del Canal Imperial, en la llamada Playa de Torrero junto a otras personas, en la puerta del estanco que regentaba en el Merendero del Canal. Puede observarse la placa, que reza "Compaâ”śâ–’â”śÂˇa Arrendataria de Tabacos", antecedente de Tabacalera. Estas instalaciones eran complementarias al embarcadero situado en la margen derecha del Canal Imperial de Aragâ”śâ”‚n, junto al puente de Amâ”śÂ®rica (a la izquierda, fuera de plano) y frente al cuartel de Castillejos. Fuente: Colecciâ”śâ”‚n Josâ”śÂ® Ignacio Larraz Vileta, a travâ”śÂ®s de Heraldo de Aragâ”śâ”‚n.', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63331000, -0.88629700, '0101000020E6100000895FB1868B5CECBF691D554D10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32353502266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32353502266.webp', 'https://www.flickr.com/photos/zaragozaantigua/32353502266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21434, 'Canal Imperial c.1915', 'Imagen del Canal Imperial y la playa de Torrero capturada desde el puente de Amâ”śÂ®rica y convertida en postal por la fototipia Ediciâ”śâ”‚n Thomas. Centra la imagen la draga del Canal estacionada junto al dique de carena o dâ”śĂ­rsena del antiguo puerto de Miraflores. A la izquierda, la playa de Torrero. Al fondo, la imponente torre de Dâ”śĂ­maso Pina. A la derecha, los viveros municipales. Fuente visual: www.todocoleccion.net/', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37372494200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37372494200.webp', 'https://www.flickr.com/photos/zaragozaantigua/37372494200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21549, 'Canal Imperial c.1925', 'Imagen parcial de la arbolada Playa de Torrero, desde el mirador a la izquierda del Puente de Amâ”śÂ®rica. Al fondo, la torre de Dâ”śĂ­maso Pina. Fuente visual: F. Mesas, en AMZ.', 1925, 1925, 1925, 'Anos 20', 'TORRERO', 41.63312600, -0.88343300, '0101000020E61000001FA166481545ECBFA71FD4450AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20469601681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20469601681.webp', 'https://www.flickr.com/photos/zaragozaantigua/20469601681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21721, 'San Fernando 1930', 'Imagen de la iglesia neoclâ”śĂ­sica de San Fernando.', 1930, 1930, 1930, 'Anos 30', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163724879.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163724879.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163724879/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21722, 'Vâ”śÂˇa de San Fernando 1931', 'Una antigua vista de cuando nieva en Zaragoza. Este entorno tan arrabalero de postal, tan centroeuropeo por lo insâ”śâ”‚lito de la blanca cubierta, junto a la neoclâ”śĂ­sica fâ”śĂ­brica del edificio de la Iglesia de San Fernando. La acequia del Plano, a la izquierda, que toma agua del Canal en la Almenara de Sta. Engracia, daba riego a los huertos de la zona, y alimentaba despuâ”śÂ®s al lavadero de La Balseta, y a los molinos de aceite, harina, e incluso temporalmente de aguardiente, en el final del Camino de San Josâ”śÂ®. A este camino, mucho despuâ”śÂ®s se la denominâ”śâ”‚ "Vâ”śÂˇa" porque no fue ni calle hasta bien entrados los aâ”śâ–’os 60 del siglo XX. Hasta entonces fue un tranquilo camino rural que enlazaba la Avenida Siglo XX con el Camino de S. Josâ”śÂ®. Apenas a diez minutos del "Centro", otro mundo. Fuente visual: Revista "Aragâ”śâ”‚n", SIPA, diciembre 1931.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63487400, -0.88315400, '0101000020E6100000569C6A2DCC42ECBF558A1D8D43D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20301250452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20301250452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20301250452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21723, 'San Fernando 1930', 'Imagen de la iglesia neoclâ”śĂ­sica de San Fernando.', 1930, 1930, 1930, 'Anos 30', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20324205716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20324205716.webp', 'https://www.flickr.com/photos/zaragozaantigua/20324205716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21769, 'Casa Bergua 1933', 'Imagen de la racionalista y singular "casa particular" de Matâ”śÂˇas Bergua Olivâ”śĂ­n, obra del arquitecto Rafael Bergamâ”śÂˇn, en la achaflanada esquina entre el paseo de Ruiseâ”śâ–’ores y el paseo del Canal. Esta vista ha sido capturada desde la confluencia de ambos paseos. Al fondo, a la izquierda, excepcional y parcial vista de los tejados de la original Residencia de Estudiantes de la Universidad de Zaragoza. Fuente visual: "Arquitectura" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63423200, -0.89016700, '0101000020E6100000514F1F813F7CECBFD009A1832ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22642430775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22642430775.webp', 'https://www.flickr.com/photos/zaragozaantigua/22642430775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21807, 'Canal Imperial 1935', '"Canal Imperial al seu pas per l''arsenal de Saragossa". Imagen capturada desde la margen izquierda del Canal Imperial en el entorno del antiguo puerto de Miralflores y centrado en una de las grandes barcas de transporte canalino ubicadas (vista parcial a la derecha) junto al dique de carena de reparaciâ”śâ”‚n de embarcaciones que en algunas fuentes es referido como "arsenal". Adaptadas al gâ”śĂ­libo del modernista puente de Amâ”śÂ®rica, estas barcazas solâ”śÂˇan ser utilizadas para traer materiales de construcciâ”śâ”‚n de la nueva barriada de Venecia. Al fondo, tras el "arsenal", luminosa fachada del referencial inmueble del nâ”¬â•‘ 1 de la vâ”śÂˇa de Pignatelli, esquinero con la avenida de Amâ”śÂ®rica. Fuente visual: Fotografâ”śÂˇa de S. Gosâ”śÂ® en Arxiu Nacional de Catalunya.', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63319200, -0.88453700, '0101000020E61000003143E389204EECBF5F0B7A6F0CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28506821518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28506821518.webp', 'https://www.flickr.com/photos/zaragozaantigua/28506821518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21959, 'San Fernando 1949', '"Fachada de la Iglesia de San Fernando de Torrero. Campanario". Fuente visual: AHPZ, Archivo Coyne', 1949, 1949, 1949, 'Anos 40', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20177382188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20177382188.webp', 'https://www.flickr.com/photos/zaragozaantigua/20177382188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22001, 'Capuchinos 1946', 'Imagen de las traseras del Sacrario Militare Italiano, o "Torre Funeraria, Iglesia y Convento de Capuchinos en Zaragoza para Panteâ”śâ”‚n de italianos muertos en la cruzada espaâ”śâ–’ola y servicios de culto". El conjunto ya ha sido finalizado (Torre e Iglesia, a la izquierda; Convento, a la derecha) y esta zona, recayente a la calle de las Escuelas, redenominada Maestro Estremiana, estaba comenzando a ser urbanizada. La vegetaciâ”śâ”‚n de primer plano, a la izquierda, ribereâ”śâ–’a de un brazal de la acequia de Ontanar. Fuente visual: La arquitectura de Vâ”śÂˇctor Eusa, Fernando Tabuenca Gonzâ”śĂ­lez.', 1946, 1946, 1946, 'Anos 40', 'TORRERO', 41.63500400, -0.88744500, '0101000020E610000084F57F0EF365ECBF236AA2CF47D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33689135640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33689135640.webp', 'https://www.flickr.com/photos/zaragozaantigua/33689135640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22053, 'Canal Imperial 1956', '1956. Josâ”śÂ® Antonio Duce captura un instante del atardecer canicular en la "Playa de Torrero". A la izquierda, en la otra orilla, Torrero, y sus edificios vinculados al Canal Imperial. A este lado, la playa y el acuartelamiento de Castillejos. Pasa un coche y levanta una polvareda. A nadie le importa. Los paseantes van hacia el Puente de Amâ”śÂ®rica.', 1956, 1956, 1956, 'Anos 50', 'TORRERO', 41.63333400, -0.88388900, '0101000020E6100000A1698995D148ECBFF1B8A81611D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897909156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897909156.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897909156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22337, 'Paseo de Cuâ”śÂ®llar 1969', 'Cruce de tranvâ”śÂˇas de la lâ”śÂˇnea 5 (Torrero) en el Paseo Cuâ”śÂ®llar a la altura del Acuartelamiento de Castillejos (derecha). Al fondo, la arboleda del Parque Pignatelli. Los tranvâ”śÂˇas son de la serie 50-65, construidos en Carde y Escoriaza en 1925, y llevan remolque de la serie 70. Fuente: "Los tranvâ”śÂˇas de Zaragoza", J. Peâ”śâ–’a - J. M. Valero, DPZ, 1985.', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63462500, -0.88487100, '0101000020E6100000DCB8C5FCDC50ECBFAC1C5A643BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20045559389.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20045559389.webp', 'https://www.flickr.com/photos/zaragozaantigua/20045559389/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22346, 'La Balseta 1961', 'Dibujo de "la Balseta" realizado por Luis Basurte como recuerdo del antiguo y desaparecido lavadero de ese nombre al final de la cuesta de Morâ”śâ”‚n, en la avenida de San Josâ”śÂ®. Los edificios del fondo, desaparecidos, eran viviendas conocidas como "el Molino Rosa". Ahora hay en su lugar el moderno bloque de viviendas del nâ”¬â•‘ 209 de la avenida. A la derecha, la Salle Torrero. Fuente visual: AVV. San Josâ”śÂ®.', 1961, 1961, 1961, 'Anos 60', 'TORRERO', 41.63428900, -0.88155600, '0101000020E610000062F6B2EDB435ECBF359BC76130D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20318416672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20318416672.webp', 'https://www.flickr.com/photos/zaragozaantigua/20318416672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22409, 'Calle Maestro Estremiana 1968', 'Imagen de la reciâ”śÂ®n inaugurada residencia de la ONCE para seâ”śâ–’oritas invidentes Nuestra Seâ”śâ–’ora del Pilar, en la calle del Maestro Estremiana 25-27, regida por religiosas de la Congregaciâ”śâ”‚n de Hermanas Angâ”śÂ®licas. Desde 1989 alojaba ancianos y fue clausurada en 2006. El edificio pervive, reconvertido y recrecido. Fuente: Agencia EFE.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63524200, -0.88806900, '0101000020E6100000F2ECF2AD0F6BECBFD7851F9C4FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24587873126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24587873126.webp', 'https://www.flickr.com/photos/zaragozaantigua/24587873126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22509, 'La Balseta, c.1965', 'Imagen capturada desde la relativa altura de las casas para empleados del Canal Imperial de la calle del Barâ”śâ”‚n de La Linde, centrada en el antiguo lavadero pâ”śâ•‘blico de La Balseta, al final de la avenida de San Josâ”śÂ®. En esta extraordinaria fotografâ”śÂˇa se aprecia perfectamente la moderna cobertura para resguardo de sol y lluvia, cuyas muestras de deterioro se fueron agravando por falta de mantenimiento hasta el derribo final de este lavadero a comienzos de la dâ”śÂ®cada de los convulsos aâ”śâ–’os 70. Era el lavadero mâ”śĂ­s antiguo de la ciudad, realizado cuando a finales del siglo XVIII llegâ”śâ”‚ hasta aquâ”śÂˇ el agua del Canal Imperial de Aragâ”śâ”‚n. En el momento de realizar la fotografâ”śÂˇa se aprecia la sombra junto al agua de una lavandera faenando con ropa. Al fondo, tramo de los nâ”śâ•‘meros 205-211 de la avenida, entre una calle sin nombre que a la izquierda conducâ”śÂˇa a la calle de Luis Royo Villanova, y el cauce al aire de la acequia del Plano a la derecha (fuera de plano), que tras surtir del agua a la Balseta hacâ”śÂˇa lo propio con el antiguo "Molino Rosa" y, mâ”śĂ­s abajo, llegaba a la harinera de la Industrial SAPASA.(antigua de Morâ”śâ”‚n).', 1965, 1965, 1965, 'Anos 60', 'TORRERO', 41.63431300, -0.88157700, '0101000020E610000040FCFCF7E035ECBFBD361B2B31D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50917833316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50917833316.webp', 'https://www.flickr.com/photos/zaragozaantigua/50917833316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
